/// 2200-PROCESS-RECORD-BY-TYPE
fn p_2200_process_record_by_type(state: &mut ProgramState) {
    if state.export_record.export_rec_type.to_string() == "C" {
        p_2300_process_customer_record(state);
    } else {
        if state.export_record.export_rec_type.to_string() == "A" {
            p_2400_process_account_record(state);
        } else {
            if state.export_record.export_rec_type.to_string() == "X" {
                p_2500_process_xref_record(state);
            } else {
                if state.export_record.export_rec_type.to_string() == "T" {
                    p_2600_process_tran_record(state);
                } else {
                    if state.export_record.export_rec_type.to_string() == "D" {
                        p_2650_process_card_record(state);
                    } else {
                        if true {
                            p_2700_process_unknown_record(state);
                        }
                    }
                }
            }
        }
    }
}

