    { let _src = state.tran_merchant_city.as_bytes(); let _end = (202+50).min(_buf.len()); let _cl = _src.len().min(_end-202); _buf[202..202+_cl].copy_from_slice(&_src[.._cl]); }
    { let _src = state.tran_merchant_zip.as_bytes(); let _end = (252+10).min(_buf.len()); let _cl = _src.len().min(_end-252); _buf[252..252+_cl].copy_from_slice(&_src[.._cl]); }
    { let _src = state.tran_card_num.as_bytes(); let _end = (262+16).min(_buf.len()); let _cl = _src.len().min(_end-262); _buf[262..262+_cl].copy_from_slice(&_src[.._cl]); }
    { let _src = state.tran_orig_ts.as_bytes(); let _end = (278+26).min(_buf.len()); let _cl = _src.len().min(_end-278); _buf[278..278+_cl].copy_from_slice(&_src[.._cl]); }
